$(document).ready(function(){window.BXReady.Market.MenuHoverList={LG:4,MD:3,SM:2,XS:1,bIMG:"N",init:function(b){b=typeof b!=="undefined"?b:$(".bxr-list-hover-menu");var a=this;b.each(function(d,c){($(c).data("lg")!=undefined&&$(c).data("lg")!="")?a.LG=$(c).data("lg"):a.LG=a.LG;($(c).data("md")!=undefined&&$(c).data("md")!="")?a.MD=$(c).data("md"):a.MD=a.MD;($(c).data("sm")!=undefined&&$(c).data("sm")!="")?a.SM=$(c).data("sm"):a.SM=a.SM;($(c).data("xs")!=undefined&&$(c).data("xs")!="")?a.XS=$(c).data("xs"):a.XS=a.XS;($(c).data("bimg")!=undefined)?a.bIMG=$(c).data("bimg"):a.bIMG=a.bIMG;new_element=$(c);if(a.bIMG!="N"&&$(c).data("bimgsrc")!=undefined&&$(c).data("bimgsrc")!=""){$(c).append("<div class='col-lg-3 col-md-3 col-sm-3 col-xs-3 bxr-element-big-image pull-"+a.bIMG+"'><img src=\""+$(c).data("bimgsrc")+"\"></div><div class='bxr-container-hover-menu col-lg-9 col-md-9 col-sm-9 col-xs-9'></div>");new_element=new_element.find(".bxr-container-hover-menu")}for(i=0;i<4;i++){new_element.append("<div class='col-lg-"+(12/a.LG)+" col-md-"+(12/a.MD)+" col-sm-"+(12/a.SM)+" col-xs-"+(12/a.XS)+" columns-left'></div>")}});$(window).resize(function(){window.BXReady.Market.MenuHoverList.menu_columns(b)});this.menu_columns(b)},isScreen:function(){if($(window).outerWidth()>=1200){return"lg"}if($(window).outerWidth()<1200&&$(window).outerWidth()>=992){return"md"}if($(window).outerWidth()<992&&$(window).outerWidth()>=768){return"sm"}if($(window).outerWidth()<768){return"xs"}return"lg"},menu_columns:function(c){var a=this.isScreen();if(c.data("rScreen")==a){return false}c.find(".columns-left").html("");var b=this[a];c.each(function(f,e){var d=0;b=$(e).data(a);$(e).find("> .bxr-element-hover-menu").each(function(g,h){if(d>=(b)||d<0){d=0}var j=$(e).find("div.columns-left:eq("+d+")");j.append($(h).clone().addClass("show col-xs-12"));++d})});c.data("rScreen",a)}};$(document).ready(function(){window.BXReady.Market.MenuHoverList.init()})});